function cleanText(html) {
  return html
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function generateHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0;
  }
  return Math.abs(hash).toString(16) + str.length;
}

const results = [];
const seenIds = new Set();

for (const item of items) {
  const html = item.json.html || item.json.textAsHtml || "";
  const text = cleanText(html);

  const blocos = text.split(/(TRT-\d+PJE|DJEN|DEOAB)/g);

  for (let i = 1; i < blocos.length; i += 2) {
    const tipo = blocos[i];
    const texto = blocos[i + 1] || "";

    const processoMatch = texto.match(/\d{7}-\d{2}\.\d{4}\.\d{1}\.\d{2}\.\d{4}/)
      || texto.match(/\d{2}\.\d{4}\.\d{4}\.\d{6}-\d/);

    const dataMatch = texto.match(/Disponibilização:\s*(\d{2})\/(\d{2})\/(\d{4})/);
    const orgaoMatch = texto.match(/(\d+ª Vara|\d+ª Turma)/);

    let dataISO = null;
    if (dataMatch) {
      dataISO = `${dataMatch[3]}-${dataMatch[2]}-${dataMatch[1]}`; // yyyy-mm-dd
    }

    const id = tipo + "_" + generateHash(texto);

    if (texto.length > 50 && !seenIds.has(id)) {
      seenIds.add(id);
      results.push({
        json: {
          id,
          tipo,
          processo: processoMatch ? processoMatch[0] : null,
          dataDisponibilizacao: dataMatch ? dataMatch[0].split(': ')[1] : null,
          dataPublicacaoISO: dataISO,
          createdAt: new Date().toISOString(),
          orgao: orgaoMatch ? orgaoMatch[1] : null,
          descricao: texto,
          lida: false,
          raw: texto
        }
      });
    }
  }
}

return results;

